#include "mpu6050.h"
#include <Wire.h>
#include <Adafruit_Sensor.h>
static Adafruit_MPU6050 mpu;
static float _ax=0,_ay=0,_az=0,_gx=0,_gy=0,_gz=0,_t=0;
static unsigned long _last=0;
void mpu6050_setup() {
  Wire.begin();
  if (!mpu.begin()) { Serial.println("[mpu6050] Init failed!"); return; }
  mpu.setAccelerometerRange(MPU6050_RANGE_8_G);
  mpu.setGyroRange(MPU6050_RANGE_500_DEG);
  mpu.setFilterBandwidth(MPU6050_BAND_21_HZ);
  Serial.println("[mpu6050] OK");
}
void mpu6050_loop() {
  if (millis()-_last < 50) return;
  _last = millis();
  sensors_event_t a, g, temp;
  mpu.getEvent(&a, &g, &temp);
  _ax=a.acceleration.x; _ay=a.acceleration.y; _az=a.acceleration.z;
  _gx=g.gyro.x; _gy=g.gyro.y; _gz=g.gyro.z;
  _t=temp.temperature;
}
float mpu6050_get_accel_x(){return _ax;}
float mpu6050_get_accel_y(){return _ay;}
float mpu6050_get_accel_z(){return _az;}
float mpu6050_get_gyro_x(){return _gx;}
float mpu6050_get_gyro_y(){return _gy;}
float mpu6050_get_gyro_z(){return _gz;}
float mpu6050_get_temperature(){return _t;}
